612	func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
613		if eventSink != nil {
614			defer eventSink.Close() //nolint:errcheck
615		}
616		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
617	
618		var worker *agent.ExecuteBeadWorker
619		if m.BeadWorkerFactory != nil {
620			worker = m.BeadWorkerFactory(store)
621		} else {
622			// Build an executor that calls agent.ExecuteBead in-process, then
623			// submits the result to the project's land coordinator. The
624			// coordinator (a single goroutine per projectRoot) serializes all
625			// target-ref writes for this project — this is the server-side
626			// implementation of the human-PR landing model. See ddx-8746d8a6
627			// for the rationale. Prior to this rewrite, runWorker never called
628			// LandBeadResult at all, so commits produced by server-managed
629			// workers were silently lost (ddx-e14efc58).
630			coordinator := m.LandCoordinators.Get(projectRoot)
631	
632			// singleTierAttempt runs one execution at a specific harness/model.
633			singleTierAttempt := func(ctx context.Context, beadID string, tier escalation.ModelTier, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
634				gitOps := &agent.RealGitOps{}
635				attemptProvider := spec.Provider
636				if resolvedProvider != "" {
637					attemptProvider = resolvedProvider
638				}
639				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
640					Harness:           resolvedHarness,
641					Model:             resolvedModel,
642					Provider:          attemptProvider,
643					ModelRef:          spec.ModelRef,
644					Effort:            spec.Effort,
645					OpaquePassthrough: spec.OpaquePassthrough,
646				})
647				beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
648				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
649					BeadEvents: beadStore,
650					BeadCancel: beadStore,
651				}, gitOps)
652				if err != nil && res == nil {
653					return agent.ExecuteBeadReport{}, err
654				}
655				// Preserve operator-cancel results as-is; the worker has already
656				// classified them (preserved / operator_cancel / preserved_needs_review)
657				// and overriding here would lose the cancel signal.
658				operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
659				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
660					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
661						err = landErr
662					}
663				} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
664					res.Outcome = "no-changes"
665					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
666				} else if res != nil && res.ExitCode != 0 && !operatorCancel {
667					res.Outcome = "preserved"
668					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
669				}
670				// Safety net: commit any leftover evidence files that Land()
671				// did not pick up (e.g. HEAD was detached, or no land ran).
672				if res != nil && res.AttemptID != "" {
673					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
674				}
675				if err != nil {
676					return agent.ExecuteBeadReport{}, err
677				}
678				tierStr := ""
679				if tier != "" {
680					tierStr = string(tier)
681				}
682				return agent.ExecuteBeadReport{
683					BeadID:             res.BeadID,
684					AttemptID:          res.AttemptID,
685					WorkerID:           res.WorkerID,
686					Harness:            res.Harness,
687					Provider:           res.Provider,
688					Model:              res.Model,
689					ActualPower:        res.ActualPower,
690					Tier:               tierStr,
691					Status:             res.Status,
692					Detail:             res.Detail,
693					SessionID:          res.SessionID,
694					BaseRev:            res.BaseRev,
695					ResultRev:          res.ResultRev,
696					PreserveRef:        res.PreserveRef,
697					NoChangesRationale: res.NoChangesRationale,
698					CostUSD:            res.CostUSD,
699					DurationMS:         int64(res.DurationMS),
700				}, nil
701			}
702	
703			// Cost-cap state for this worker run. Subscription / local providers do
704			// not contribute (see escalation.CountsTowardCostCap).
705			// TODO(ddx-785d02f7): expose maxCostUSD as a worker spec field
706			// once the spec config knob lands.
707			costCap := escalation.NewCostCapTracker(escalation.DefaultMaxCostUSD, func(harnessName string) bool {
708				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
709				if svcErr != nil {
710					return true
711				}
712				infos, err := svc.ListHarnesses(context.Background())
713				if err != nil {
714					return true
715				}
716				for _, h := range infos {
717					if h.Name == harnessName {
718						return escalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
719					}
720				}
721				return true
722			})
723			accumulateBilledCost := func(report agent.ExecuteBeadReport) {
724				costCap.Add(report.Harness, report.CostUSD)
725			}
726			costCapTripped := func() (agent.ExecuteBeadReport, bool) {
727				detail, tripped := costCap.Tripped()
728				if !tripped {
729					return agent.ExecuteBeadReport{}, false
730				}
731				return agent.ExecuteBeadReport{
732					Status: agent.ExecuteBeadStatusExecutionFailed,
733					Detail: detail,
734				}, true
735			}
736	
737			executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
738				if cappedReport, capped := costCapTripped(); capped {
739					cappedReport.BeadID = beadID
740					return cappedReport, nil
741				}
742				report, err := singleTierAttempt(ctx, beadID, "", spec.Harness, spec.Provider, spec.Model)
743				if err == nil {
744					accumulateBilledCost(report)
745					if cappedReport, capped := costCapTripped(); capped {
746						cappedReport.BeadID = beadID
747						return cappedReport, nil
748					}
749				}
750				return report, err
751			})
752	
753			// Build post-merge reviewer. On-by-default unless NoReview is set in spec.
754			var reviewer agent.BeadReviewer
755			if !spec.NoReview {
756				reviewer = &agent.DefaultBeadReviewer{
757					ProjectRoot: projectRoot,
758					BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
759					BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
760					Harness:     spec.ReviewHarness,
761					Model:       spec.ReviewModel,
762				}
763			}
764	
765			worker = &agent.ExecuteBeadWorker{
766				Store:    store,
767				Executor: executor,
768				Reviewer: reviewer,
769			}
770		}
771	
772		// SD-024 Stage 1: server dispatch flows through LoadAndResolve +
773		// RunWithConfig so .ddx/config.yaml's durable knobs (review_max_retries,
774		// no_progress_cooldown, max_no_changes_before_close, heartbeat_interval,
