type ExecuteBeadRuntime struct {
	FromRev     string // base git revision (default: HEAD)
	PromptFile  string // override prompt file (auto-generated if empty)
	WorkerID    string // from DDX_WORKER_ID env or caller
	BeadEvents  BeadEventAppender
	BeadCancel  BeadCancelStore // optional: enables operator-cancel mid-attempt poll
	Service     agentlib.FizeauService
	AgentRunner AgentRunner
	// Role identifies the calling role for routing telemetry. Defaults to
	// "implementer" when empty. Forwarded onto ServiceExecuteRequest.Role.
	Role string
	// MinPowerOverride, when > 0, overrides rcfg.MinPower() for this single
	// invocation. Used by the executor closure's ladder-driven retry to bump
	// the power floor between attempts on the same bead claim.
	MinPowerOverride int
}

