type ExecuteBeadExecutorFunc func(ctx context.Context, beadID string) (ExecuteBeadReport, error)

func (f ExecuteBeadExecutorFunc) Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
	return f(ctx, beadID)
}

// LadderAttemptFunc runs a single execute-bead attempt at the given MinPower
// floor. It is the per-attempt seam consumed by NewLadderRetryExecutor.
type LadderAttemptFunc func(ctx context.Context, beadID string, minPower int) (ExecuteBeadReport, error)

// NewLadderRetryExecutor returns an ExecuteBeadExecutor that drives a
// MinPower-only escalation ladder. On each substantive failure it consults
// ladder.Next(report.ActualPower) to obtain the next power floor and re-runs
// attempt with that floor. The loop exits on:
//
//   - success — the bead's status is no longer escalation-worthy.
//   - non-substantive failure — e.g. infrastructure-class outages
//     (escalation.IsInfrastructureFailure) or no_changes; escalation does not
//     consume budget on these.
//   - ladder exhaustion (escalation.ErrLadderExhausted) — no higher tier
//     remains in the catalog above the last attempt's actualPower.
//
// ladder may be nil — in that case no escalation is attempted and the helper
// reduces to a single call. attempt must be non-nil.
func NewLadderRetryExecutor(ladder *agentescalation.Ladder, initialMinPower int, attempt LadderAttemptFunc) ExecuteBeadExecutor {
	return ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		minPower := initialMinPower
		for {
			report, err := attempt(ctx, beadID, minPower)
			if err != nil {
				return report, err
			}
			if !ladderShouldEscalate(report) || ladder == nil {
				return report, nil
			}
			next, lerr := ladderNextFloor(ladder, report.ActualPower)
			if lerr != nil {
				return report, nil
			}
			if next <= minPower {
				return report, nil
			}
			minPower = next
		}
	})
}

// ladderShouldEscalate reports whether the report represents a substantive
// failure that warrants moving up the ladder. Infrastructure-class failures
// (e.g. provider 502) and no_changes are not substantive — the model wasn't
// given a fair chance, or the bead reported a non-failure outcome.
func ladderShouldEscalate(report ExecuteBeadReport) bool {
	if !escalation.ShouldEscalate(report.Status) {
		return false
	}
	if escalation.IsInfrastructureFailure(report.Status, report.Detail) {
		return false
	}
	return true
}

// ladderNextFloor wraps Ladder.Next and skips past tiers that exist in the
// catalog but have no viable provider. Returns ErrLadderExhausted (or any
// other non-NoViableProvider error) when no higher viable tier remains.
func ladderNextFloor(ladder *agentescalation.Ladder, actualPower int) (int, error) {
	cursor := actualPower
	for {
		next, err := ladder.Next(cursor)
		if err == nil {
			return next, nil
		}
		var nv *agentescalation.NoViableProviderError
		if errors.As(err, &nv) {
			cursor = nv.Floor
			continue
		}
		return 0, err
	}
}

