// buildExecuteLoopLadder constructs the MinPower-only escalation ladder for
// the execute-loop. It snapshots the model catalog from the agent service,
// flagging viable tiers (Available && AutoRoutable). Failures (no service,
// catalog read error) yield a non-nil but empty Ladder — Next on it returns
// ErrLadderExhausted, which collapses NewLadderRetryExecutor to a single
// pass-through call (no escalation attempted). ddx-cfedee8e.
func buildExecuteLoopLadder(ctx context.Context, workDir string) *agentescalation.Ladder {
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil {
		return agentescalation.NewLadder(nil)
	}
	models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
	if err != nil {
		return agentescalation.NewLadder(nil)
	}
	return agentescalation.NewLadder(models)
}

