// TestNewLadderRetryExecutor_EscalatesOnSubstantiveFailure exercises the
// real ladder retry loop driven by the executor closure (ddx-cfedee8e
// AC#1, AC#4). The fake attempt fails substantively at low power, and the
// loop must consult ladder.Next(actualPower) to bump MinPower for the next
// call until a higher tier succeeds.
func TestNewLadderRetryExecutor_EscalatesOnSubstantiveFailure(t *testing.T) {
	models := []agentlib.ModelInfo{
		{Power: 30, Available: true, AutoRoutable: true},
		{Power: 60, Available: true, AutoRoutable: true},
		{Power: 90, Available: true, AutoRoutable: true},
	}
	ladder := agentescalation.NewLadder(models)

	type call struct {
		minPower int
	}
	var calls []call

	// Substantive failure at power 30 (actual=30), at 60 (actual=60), then
	// success at 90.
	attempt := func(_ context.Context, beadID string, minPower int) (ExecuteBeadReport, error) {
		calls = append(calls, call{minPower: minPower})
		switch len(calls) {
		case 1:
			return ExecuteBeadReport{
				BeadID:      beadID,
				Status:      ExecuteBeadStatusExecutionFailed,
				Detail:      "TestFoo failed: assertion mismatch",
				ActualPower: 30,
			}, nil
		case 2:
			return ExecuteBeadReport{
				BeadID:      beadID,
				Status:      ExecuteBeadStatusPostRunCheckFailed,
				Detail:      "vet failed",
				ActualPower: 60,
			}, nil
		default:
			return ExecuteBeadReport{
				BeadID:      beadID,
				Status:      ExecuteBeadStatusSuccess,
				ActualPower: 90,
			}, nil
		}
	}

	executor := NewLadderRetryExecutor(ladder, 0, attempt)
	report, err := executor.Execute(context.Background(), "ddx-test-001")
	require.NoError(t, err)
	require.Equal(t, ExecuteBeadStatusSuccess, report.Status)
	require.Len(t, calls, 3, "ladder must drive three attempts cheap → standard → smart")
	assert.Equal(t, 0, calls[0].minPower, "first call uses initial floor")
	assert.Equal(t, 60, calls[1].minPower, "after actual=30 substantive failure, ladder bumps floor to 60")
	assert.Equal(t, 90, calls[2].minPower, "after actual=60 substantive failure, ladder bumps floor to 90")
}

// TestNewLadderRetryExecutor_NoEscalateOnInfrastructure verifies that an
// infrastructure-class failure (e.g. provider 502) does NOT consume
// escalation budget. The loop returns immediately without bumping MinPower.
func TestNewLadderRetryExecutor_NoEscalateOnInfrastructure(t *testing.T) {
	models := []agentlib.ModelInfo{
		{Power: 30, Available: true, AutoRoutable: true},
		{Power: 60, Available: true, AutoRoutable: true},
	}
	ladder := agentescalation.NewLadder(models)

	calls := 0
	attempt := func(_ context.Context, beadID string, minPower int) (ExecuteBeadReport, error) {
		calls++
		return ExecuteBeadReport{
			BeadID:      beadID,
			Status:      ExecuteBeadStatusExecutionFailed,
			Detail:      "provider 502 Bad Gateway: connection refused",
			ActualPower: 30,
		}, nil
	}

	executor := NewLadderRetryExecutor(ladder, 0, attempt)
	report, err := executor.Execute(context.Background(), "ddx-test-002")
	require.NoError(t, err)
	require.Equal(t, ExecuteBeadStatusExecutionFailed, report.Status)
	require.Equal(t, 1, calls, "infrastructure failure must not bump the ladder")
}

// TestNewLadderRetryExecutor_StopsOnLadderExhaustion verifies the loop
// terminates when ladder.Next returns ErrLadderExhausted (no higher tier in
// the catalog). The final report carries the last attempt's status, not a
// synthesized exhaustion error.
func TestNewLadderRetryExecutor_StopsOnLadderExhaustion(t *testing.T) {
	models := []agentlib.ModelInfo{
		{Power: 50, Available: true, AutoRoutable: true},
	}
	ladder := agentescalation.NewLadder(models)

	calls := 0
	attempt := func(_ context.Context, beadID string, minPower int) (ExecuteBeadReport, error) {
		calls++
		return ExecuteBeadReport{
			BeadID:      beadID,
			Status:      ExecuteBeadStatusExecutionFailed,
			Detail:      "test failed",
			ActualPower: 50,
		}, nil
	}

	executor := NewLadderRetryExecutor(ladder, 0, attempt)
	report, err := executor.Execute(context.Background(), "ddx-test-003")
	require.NoError(t, err)
	require.Equal(t, ExecuteBeadStatusExecutionFailed, report.Status)
	require.Equal(t, 1, calls, "exhausted ladder yields exactly one attempt")
}

// TestNewLadderRetryExecutor_SkipsNonViableTier verifies the loop skips a
// catalog tier that exists but has no viable provider (Available=false /
// AutoRoutable=false), per Ladder.Next's NoViableProviderError contract.
func TestNewLadderRetryExecutor_SkipsNonViableTier(t *testing.T) {
	models := []agentlib.ModelInfo{
		{Power: 30, Available: true, AutoRoutable: true},
		{Power: 60, Available: false, AutoRoutable: true}, // dead tier
		{Power: 90, Available: true, AutoRoutable: true},
	}
	ladder := agentescalation.NewLadder(models)

	var floors []int
	attempt := func(_ context.Context, beadID string, minPower int) (ExecuteBeadReport, error) {
		floors = append(floors, minPower)
		switch len(floors) {
		case 1:
			return ExecuteBeadReport{
				BeadID: beadID, Status: ExecuteBeadStatusExecutionFailed,
				Detail: "tests failed", ActualPower: 30,
			}, nil
		default:
			return ExecuteBeadReport{
				BeadID: beadID, Status: ExecuteBeadStatusSuccess, ActualPower: 90,
			}, nil
		}
	}

	executor := NewLadderRetryExecutor(ladder, 0, attempt)
	report, err := executor.Execute(context.Background(), "ddx-test-004")
	require.NoError(t, err)
	require.Equal(t, ExecuteBeadStatusSuccess, report.Status)
	require.Equal(t, []int{0, 90}, floors,
		"ladder must skip non-viable power=60 and jump to power=90")
}

// nextTier advances one rung up the cheap -> standard -> smart ladder.
